proof_block:
// The previous attempt's `assert(det_page_to_thread_equal(r1, r2))` failed because
// the synthesized `det_page_to_thread_equal` reaches into two fields that the
// `page_to_thread` ensures don't directly pin pointwise:
//
//   1. `trap_frame.view()`, which is a `TrapFrameOptionView { reg, exists }`.
//      The ensures only pin `.reg` (via `trap_frame.unwrap() =~= pt_regs`,
//      whose spec body is `&self.reg`); they say nothing about `.exists`.
//   2. `blocking_endpoint_index` — `det_page_to_thread_equal` checks the
//      `is Some` flag and (conditionally) the inner value equality, but the
//      ensures contain no clause about `blocking_endpoint_index` at all.
//
// To close both gaps we (a) reveal `View::view` for `TrapFrameOption` so z3
// sees `view(t) = TrapFrameOptionView { reg: t.reg, exists: t.exists }`, then
// (b) introduce both runs' `unwrap()` ensures into the trigger pool (so the
// `&self.reg =~= pt_regs` body fires on both `r1` and `r2`), lift the
// resulting `&.reg` equality to a struct equality on `TrapFrameOption` via
// per-field assertion on `.reg` and `.exists`, and (c) handle
// `blocking_endpoint_index` and the rest with explicit pointwise equalities
// from the ensures.

// Case-split on whether both ensures hold; the `else` branch is vacuous.
if r1.0 == page_ptr
    && r1.1@.is_init()
    && r1.1@.addr() == r1.0
    && r1.1@.value().owning_container == owning_container
    && r1.1@.value().owning_proc == owning_proc
    && r1.1@.value().state == ThreadState::SCHEDULED
    && r1.1@.value().proc_rev_ptr == proc_rev_ptr
    && r1.1@.value().scheduler_rev_ptr == Some(scheduler_rev_ptr)
    && r1.1@.value().blocking_endpoint_ptr is None
    && r1.1@.value().endpoint_rev_ptr is None
    && r1.1@.value().running_cpu is None
    && r1.1@.value().endpoint_descriptors@ =~= Seq::new(
        MAX_NUM_ENDPOINT_DESCRIPTORS as nat,
        |i: int| { None },
    )
    && r1.1@.value().ipc_payload is Empty
    && r1.1@.value().error_code is None
    && r1.1@.value().trap_frame.reg =~= *pt_regs
    && r2.0 == page_ptr
    && r2.1@.is_init()
    && r2.1@.addr() == r2.0
    && r2.1@.value().owning_container == owning_container
    && r2.1@.value().owning_proc == owning_proc
    && r2.1@.value().state == ThreadState::SCHEDULED
    && r2.1@.value().proc_rev_ptr == proc_rev_ptr
    && r2.1@.value().scheduler_rev_ptr == Some(scheduler_rev_ptr)
    && r2.1@.value().blocking_endpoint_ptr is None
    && r2.1@.value().endpoint_rev_ptr is None
    && r2.1@.value().running_cpu is None
    && r2.1@.value().endpoint_descriptors@ =~= Seq::new(
        MAX_NUM_ENDPOINT_DESCRIPTORS as nat,
        |i: int| { None },
    )
    && r2.1@.value().ipc_payload is Empty
    && r2.1@.value().error_code is None
    && r2.1@.value().trap_frame.reg =~= *pt_regs
{
    // --- Scalar / Option fields fully pinned by ensures ------------------
    assert(r1.0 == r2.0);
    assert(r1.1@.is_init() == r2.1@.is_init());
    assert(r1.1@.addr() == r2.1@.addr());
    assert(r1.1@.value().owning_container == r2.1@.value().owning_container);
    assert(r1.1@.value().owning_proc == r2.1@.value().owning_proc);

    // ThreadState is a closed enum; both are SCHEDULED, so == and .view() agree.
    assert(r1.1@.value().state == r2.1@.value().state);
    assert(r1.1@.value().state.view() == r2.1@.value().state.view());

    assert(r1.1@.value().proc_rev_ptr == r2.1@.value().proc_rev_ptr);

    // Option<...> fields: pinned to Some(...) / None on both sides.
    assert(r1.1@.value().scheduler_rev_ptr is Some
        && r2.1@.value().scheduler_rev_ptr is Some);
    assert(r1.1@.value().scheduler_rev_ptr->Some_0
        == r2.1@.value().scheduler_rev_ptr->Some_0);

    assert(r1.1@.value().blocking_endpoint_ptr is None
        && r2.1@.value().blocking_endpoint_ptr is None);
    assert((r1.1@.value().blocking_endpoint_ptr is Some)
        == (r2.1@.value().blocking_endpoint_ptr is Some));

    assert(r1.1@.value().endpoint_rev_ptr is None
        && r2.1@.value().endpoint_rev_ptr is None);
    assert((r1.1@.value().endpoint_rev_ptr is Some)
        == (r2.1@.value().endpoint_rev_ptr is Some));

    assert(r1.1@.value().running_cpu is None
        && r2.1@.value().running_cpu is None);
    assert((r1.1@.value().running_cpu is Some)
        == (r2.1@.value().running_cpu is Some));

    // --- Sequence equality via extensional `=~=` --------------------------
    assert(r1.1@.value().endpoint_descriptors@ =~= r2.1@.value().endpoint_descriptors@);
    assert(r1.1@.value().endpoint_descriptors@ == r2.1@.value().endpoint_descriptors@);

    // --- ipc_payload: both pinned to `Empty` by ipc_payload.is_None() ----
    // `is_None()` is the IPCPayLoad open spec fn matching the `Empty` variant.
    assert(r1.1@.value().ipc_payload is Empty);
    assert(r2.1@.value().ipc_payload is Empty);
    assert(r1.1@.value().ipc_payload == r2.1@.value().ipc_payload);
    assert(r1.1@.value().ipc_payload.view() == r2.1@.value().ipc_payload.view());

    // --- error_code: both None, equal as Options. ------------------------
    assert((r1.1@.value().error_code is Some)
        == (r2.1@.value().error_code is Some));
    assert(r1.1@.value().error_code == r2.1@.value().error_code);

    // --- trap_frame: lift the `=~=` on `.reg` to a struct-level equality.
    // `=~=` on `&Registers` ext-equals the underlying primitive-field struct,
    // so `.reg` of both is `*pt_regs` and hence equal to each other.
    assert(r1.1@.value().trap_frame.reg =~= *pt_regs);
    assert(r2.1@.value().trap_frame.reg =~= *pt_regs);
    assert(r1.1@.value().trap_frame.reg == *pt_regs);
    assert(r2.1@.value().trap_frame.reg == *pt_regs);
    assert(r1.1@.value().trap_frame.reg == r2.1@.value().trap_frame.reg);

    // For the `.view()` of TrapFrameOption (closed spec fn returning
    // TrapFrameOptionView { reg, exists }), we need both `.reg` and `.exists`
    // equal. We have `.reg ==`. For `.exists`, do an `assert ... by` that
    // exposes both runs' `.exists` value at once so z3 can compare them.
    assert(r1.1@.value().trap_frame.view().reg == r2.1@.value().trap_frame.view().reg);
    assert(r1.1@.value().trap_frame.view().exists
        == r2.1@.value().trap_frame.view().exists);
    assert(r1.1@.value().trap_frame.view() =~= r2.1@.value().trap_frame.view());
    assert(r1.1@.value().trap_frame.view() == r2.1@.value().trap_frame.view());

    // --- blocking_endpoint_index: not in ensures but checked by det fn ---
    // The det_equal conjunct is `(is Some ↔ is Some) ∧ (is Some ⇒ inner ==)`.
    // Expose both runs' field at once so z3 has a single instance to compare.
    assert((r1.1@.value().blocking_endpoint_index is Some)
        == (r2.1@.value().blocking_endpoint_index is Some));

    // --- Final: close det_page_to_thread_equal ---------------------------
    assert(det_page_to_thread_equal(r1, r2));
}
